// Шинэ ажилтны ID-г салбараар автомат үүсгэх + давхцал шалгах
// Input: Webhook body { name, role, group, phone, email, pin }
//        + одоогийн бүх ажилтнууд (Sheets read)

const body = $('Webhook · Бүртгэл хүсэлт').first().json.body || {};
const existing = $input.all().map(it => it.json);

// ─── Validation ───
const name  = String(body.name || '').trim();
const role  = String(body.role || '').trim();
const group = String(body.group || '').trim();
const phone = String(body.phone || '').trim();
const email = String(body.email || '').trim();
const pin   = String(body.pin || '').trim();

if (!name)  throw new Error('Овог нэр шаардлагатай');
if (!role)  throw new Error('Албан тушаал шаардлагатай');
if (!group) throw new Error('Бүлэг шаардлагатай');
if (!/^\d{4}$/.test(pin)) throw new Error('PIN нь 4 оронтой тоо байх ёстой');

// ─── PIN давхцал шалгах ───
const pinExists = existing.some(r => String(r['PIN'] || '').trim() === pin);
if (pinExists) throw new Error('Энэ PIN өөр хүн ашиглаж байна');

// ─── ID prefix салбараар тогтоох ───
const PREFIX_MAP = {
  'Нэгдсэн': 'S',
  'M Event': 'M',
  'Camp':    'C',
};
const prefix = PREFIX_MAP[group] || 'X';

// ─── Дараагийн чөлөөт дугаар олох ───
const usedIds = new Set(existing.map(r => String(r['ID'] || '').trim()));
let n = 1;
let newId = prefix + String(n).padStart(2, '0');
while (usedIds.has(newId)) {
  n++;
  newId = prefix + String(n).padStart(2, '0');
}

// ─── Бүлэг → app branch mapping ───
// Master Sheet-д 'Бүлэг' баганад group нэрийг бичнэ (хэвээр)

// ─── Гаралт: Sheet-д бичих мөр ───
const today = new Date().toISOString().slice(0, 10);

return [{ json: {
  id: newId,
  name,
  role,
  group,
  phone,
  email,
  pin,
  level: 40,            // Шинэ ажилтан default зэрэглэл
  status: 'идэвхтэй',   // Шууд идэвхтэй (CEO баталгаажуулалтгүй)
  joined: today,
} }];
